example.code:
using ByteForge.Toolkit;

// String trimming and cleaning
string dirtyText = "  Hello World!  \r\n\t  ";
string cleaned = StringUtil.CleanText(dirtyText);
Console.WriteLine($"Cleaned: '{cleaned}'"); // "Hello World!"

// Safe substring operations
string text = "Hello World";
string safe1 = StringUtil.SafeSubstring(text, 0, 5);   // "Hello"
string safe2 = StringUtil.SafeSubstring(text, 6, 100); // "World" (no exception)
string safe3 = StringUtil.SafeSubstring(text, 20, 5);  // "" (no exception)

// String comparison utilities
bool equals1 = StringUtil.SafeEquals("Hello", "hello", ignoreCase: true);  // true
bool equals2 = StringUtil.SafeEquals("Test", null, ignoreCase: false);     // false
bool equals3 = StringUtil.SafeEquals(null, null, ignoreCase: false);       // true

// String formatting and templates
string template = "Hello {name}, you have {count} messages.";
var values = new Dictionary<string, object> 
{ 
    { "name", "John" }, 
    { "count", 5 } 
};
string formatted = StringUtil.FormatTemplate(template, values);
Console.WriteLine(formatted); // "Hello John, you have 5 messages."

// String validation
bool isValidEmail = StringUtil.IsValidEmail("user@example.com");     // true
bool isValidPhone = StringUtil.IsValidPhoneNumber("(555) 123-4567"); // true
bool isValidUrl = StringUtil.IsValidUrl("https://www.example.com");  // true

using ByteForge.Toolkit;

var parser = new BooleanParser();

// Standard boolean parsing
bool result1 = parser.Parse("true");   // true
bool result2 = parser.Parse("false");  // false
bool result3 = parser.Parse("TRUE");   // true (case-insensitive)

// Yes/No parsing
bool result4 = parser.Parse("yes");    // true
bool result5 = parser.Parse("no");     // false
bool result6 = parser.Parse("Y");      // true
bool result7 = parser.Parse("N");      // false

// Numeric parsing
bool result8 = parser.Parse("1");      // true
bool result9 = parser.Parse("0");      // false

// Custom string parsing
bool result10 = parser.Parse("on");    // true
bool result11 = parser.Parse("off");   // false
bool result12 = parser.Parse("enabled");  // true
bool result13 = parser.Parse("disabled"); // false

// Safe parsing with default values
bool safe1 = parser.TryParse("invalid", defaultValue: false); // false
bool safe2 = parser.TryParse("true", defaultValue: false);    // true
bool safe3 = parser.TryParse(null, defaultValue: true);       // true

// Parse from configuration or user input
var configValues = new Dictionary<string, string>
{
    { "EnableLogging", "yes" },
    { "DebugMode", "1" },
    { "SendEmails", "off" },
    { "UseCompression", "enabled" },
    { "InvalidSetting", "maybe" }
};

foreach (var setting in configValues)
{
    try
    {
        bool value = parser.Parse(setting.Value);
        Console.WriteLine($"{setting.Key}: {value}");
    }
    catch (FormatException)
    {
        bool defaultValue = parser.TryParse(setting.Value, defaultValue: false);
        Console.WriteLine($"{setting.Key}: {defaultValue} (using default)");
    }
}

using ByteForge.Toolkit;
using System.Globalization;

var parser = new DateTimeParser();

// Standard date parsing
DateTime date1 = parser.Parse("2024-01-15");              // ISO format
DateTime date2 = parser.Parse("01/15/2024");              // US format
DateTime date3 = parser.Parse("15/01/2024");              // European format
DateTime date4 = parser.Parse("January 15, 2024");        // Long format

// Time parsing
DateTime time1 = parser.Parse("14:30:00");                // 24-hour
DateTime time2 = parser.Parse("2:30 PM");                 // 12-hour
DateTime time3 = parser.Parse("2:30:45.123 PM");          // With milliseconds

// Date and time combinations
DateTime dt1 = parser.Parse("2024-01-15 14:30:00");
DateTime dt2 = parser.Parse("January 15, 2024 2:30 PM");
DateTime dt3 = parser.Parse("15/01/2024 14:30");

// Relative date parsing
DateTime now = DateTime.Now;
DateTime yesterday = parser.ParseRelative("yesterday");
DateTime tomorrow = parser.ParseRelative("tomorrow");
DateTime nextWeek = parser.ParseRelative("next week");
DateTime lastMonth = parser.ParseRelative("last month");

// Culture-specific parsing
var frenchCulture = new CultureInfo("fr-FR");
var germanCulture = new CultureInfo("de-DE");

parser.SetCulture(frenchCulture);
DateTime frenchDate = parser.Parse("15 janvier 2024");

parser.SetCulture(germanCulture);
DateTime germanDate = parser.Parse("15. Januar 2024");

// Safe parsing with defaults
DateTime safe1 = parser.TryParse("invalid date", DateTime.MinValue);
DateTime safe2 = parser.TryParse("2024-01-15", DateTime.MinValue);
DateTime safe3 = parser.TryParse(null, DateTime.Now);

// Parse from various input sources
var dateInputs = new[]
{
    "2024-01-15",
    "01/15/2024",
    "15-Jan-2024",
    "Monday, January 15, 2024",
    "yesterday",
    "next Friday",
    "invalid",
    ""
};

Console.WriteLine("Date parsing results:");
foreach (var input in dateInputs)
{
    try
    {
        var parsed = parser.Parse(input);
        Console.WriteLine($"'{input}' -> {parsed:yyyy-MM-dd HH:mm:ss}");
    }
    catch (FormatException)
    {
        var fallback = parser.TryParse(input, DateTime.MinValue);
        Console.WriteLine($"'{input}' -> Could not parse (using fallback: {fallback:yyyy-MM-dd})");
    }
}

using ByteForge.Toolkit;

// Safe file operations
string sourceFile = @"C:\Data\largefile.zip";
string destFile = @"C:\Backup\largefile.zip";

// Copy file with progress reporting
var progress = new Progress<FileOperationProgress>(p =>
{
    Console.WriteLine($"Copying: {p.PercentComplete:F1}% ({p.BytesProcessed:N0}/{p.TotalBytes:N0} bytes)");
});

await IOUtils.CopyFileAsync(sourceFile, destFile, progress);

// Move file safely
string moveSource = @"C:\Temp\document.pdf";
string moveDestination = @"C:\Archive\document.pdf";
IOUtils.MoveFileSafe(moveSource, moveDestination);

// Create directory structure
string complexPath = @"C:\Projects\MyApp\Data\Logs\2024\January";
IOUtils.EnsureDirectoryExists(complexPath);

// Get directory size with progress
var sizeProgress = new Progress<DirectoryScanProgress>(p =>
{
    Console.WriteLine($"Scanning: {p.FilesScanned} files, {p.TotalSize:N0} bytes");
});

long totalSize = await IOUtils.GetDirectorySizeAsync(@"C:\Projects", sizeProgress);
Console.WriteLine($"Total directory size: {totalSize:N0} bytes ({totalSize / 1024.0 / 1024.0:F1} MB)");

// Find files with pattern
var logFiles = IOUtils.FindFiles(@"C:\Logs", "*.log", SearchOption.AllDirectories);
Console.WriteLine($"Found {logFiles.Count()} log files");

// Clean up old files
int deletedCount = IOUtils.CleanupOldFiles(@"C:\Temp", TimeSpan.FromDays(30));
Console.WriteLine($"Deleted {deletedCount} files older than 30 days");

// Get file information
var fileInfo = IOUtils.GetFileInfo(sourceFile);
Console.WriteLine($"File: {fileInfo.Name}");
Console.WriteLine($"Size: {fileInfo.Size:N0} bytes");
Console.WriteLine($"Created: {fileInfo.CreatedDate:yyyy-MM-dd HH:mm:ss}");
Console.WriteLine($"Modified: {fileInfo.ModifiedDate:yyyy-MM-dd HH:mm:ss}");
Console.WriteLine($"Read-only: {fileInfo.IsReadOnly}");

// Batch file operations
var filesToProcess = Directory.GetFiles(@"C:\DataToProcess", "*.txt");
await IOUtils.ProcessFilesAsync(filesToProcess, async file =>
{
    // Process each file
    var content = await File.ReadAllTextAsync(file);
    var processedContent = content.ToUpper();
    await File.WriteAllTextAsync(file + ".processed", processedContent);
}, maxConcurrency: 4);

