// Custom template functions
processor.RegisterFunction("FormatCurrency", (object[] args) =>
{
    if (args.Length >= 2 && decimal.TryParse(args[0].ToString(), out decimal amount))
    {
        string currency = args[1].ToString();
        return currency switch
        {
            "USD" => $"${amount:F2}",
            "EUR" => $"€{amount:F2}",
            "GBP" => $"£{amount:F2}",
            _ => $"{amount:F2} {currency}"
        };
    }
    return args[0]?.ToString() ?? "";
});

