using ByteForge.Toolkit;

var registry = new ValueConverterRegistry();

// Register custom converters
registry.RegisterConverter<string, Color>(colorString =>
{
    return colorString.ToLower() switch
    {
        "red" => Color.FromArgb(255, 0, 0),
        "green" => Color.FromArgb(0, 255, 0),
        "blue" => Color.FromArgb(0, 0, 255),
        _ => ColorTranslator.FromHtml(colorString)
    };
});

registry.RegisterConverter<string, TimeSpan>(timeString =>
{
    // Parse formats like "2h 30m", "1.5h", "90m"
    if (timeString.Contains("h") && timeString.Contains("m"))
    {
        var parts = timeString.Replace("h", "").Replace("m", "").Split(' ', StringSplitOptions.RemoveEmptyEntries);
        int hours = int.Parse(parts[0]);
        int minutes = int.Parse(parts[1]);
        return TimeSpan.FromHours(hours).Add(TimeSpan.FromMinutes(minutes));
    }
    else if (timeString.EndsWith("h"))
    {
        double hours = double.Parse(timeString.Replace("h", ""));
        return TimeSpan.FromHours(hours);
    }
    else if (timeString.EndsWith("m"))
    {
        int minutes = int.Parse(timeString.Replace("m", ""));
        return TimeSpan.FromMinutes(minutes);
    }

    return TimeSpan.Parse(timeString);
});

// Use converters
Color redColor = registry.Convert<string, Color>("red");
Color hexColor = registry.Convert<string, Color>("#FF5733");
TimeSpan duration1 = registry.Convert<string, TimeSpan>("2h 30m");
TimeSpan duration2 = registry.Convert<string, TimeSpan>("1.5h");
TimeSpan duration3 = registry.Convert<string, TimeSpan>("90m");

Console.WriteLine($"Red color: R={redColor.R}, G={redColor.G}, B={redColor.B}");
Console.WriteLine($"Hex color: R={hexColor.R}, G={hexColor.G}, B={hexColor.B}");
Console.WriteLine($"Duration 1: {duration1.TotalMinutes} minutes");
Console.WriteLine($"Duration 2: {duration2.TotalMinutes} minutes");
Console.WriteLine($"Duration 3: {duration3.TotalMinutes} minutes");

// Batch conversion from configuration
var configValues = new Dictionary<string, string>
{
    { "BackgroundColor", "#F0F0F0" },
    { "TextColor", "blue" },
    { "WarningColor", "orange" },
    { "SessionTimeout", "30m" },
    { "CacheExpiry", "2h" },
    { "RetryDelay", "500ms" }
};

var convertedConfig = new Dictionary<string, object>();

foreach (var kvp in configValues)
{
    try
    {
        if (kvp.Key.Contains("Color"))
        {
            convertedConfig[kvp.Key] = registry.Convert<string, Color>(kvp.Value);
        }
        else if (kvp.Key.Contains("Timeout") || kvp.Key.Contains("Expiry") || kvp.Key.Contains("Delay"))
        {
            convertedConfig[kvp.Key] = registry.Convert<string, TimeSpan>(kvp.Value);
        }
        else
        {
            convertedConfig[kvp.Key] = kvp.Value;
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Failed to convert {kvp.Key}: {kvp.Value} - {ex.Message}");
        convertedConfig[kvp.Key] = kvp.Value; // Keep original value
    }
}

Console.WriteLine("\nConverted configuration:");
foreach (var kvp in convertedConfig)
{
    Console.WriteLine($"{kvp.Key}: {kvp.Value} (Type: {kvp.Value.GetType().Name})");
}

using ByteForge.Toolkit;
using System;
using System.Collections.Generic;
using System.IO;
using System.Threading.Tasks;

// Data processing application using multiple utilities
public class DataProcessingService
{
    private readonly BooleanParser _boolParser;
    private readonly DateTimeParser _dateParser;
    private readonly TemplateProcessor _templateProcessor;
    private readonly ValueConverterRegistry _converterRegistry;

    public DataProcessingService()
    {
        _boolParser = new BooleanParser();
        _dateParser = new DateTimeParser();
        _templateProcessor = new TemplateProcessor();
        _converterRegistry = new ValueConverterRegistry();

        ConfigureCustomConverters();
    }

    private void ConfigureCustomConverters()
    {
        // Register custom converters for configuration
        _converterRegistry.RegisterConverter<string, FileSize>(sizeString =>
        {
            var units = new Dictionary<string, long>
            {
                { "B", 1L },
                { "KB", 1024L },
                { "MB", 1024L * 1024L },
                { "GB", 1024L * 1024L * 1024L }
            };

            foreach (var unit in units)
            {
                if (sizeString.ToUpper().EndsWith(unit.Key))
                {
                    var numberPart = sizeString[..^unit.Key.Length].Trim();
                    if (double.TryParse(numberPart, out double value))
                    {
                        return new FileSize((long)(value * unit.Value));
                    }
                }
            }

            // Try parsing as just a number (assume bytes)
            if (long.TryParse(sizeString, out long bytes))
            {
                return new FileSize(bytes);
            }

            throw new FormatException($"Invalid file size format: {sizeString}");
        });
    }

    public async Task ProcessConfigurationFile(string configPath)
    {
        Console.WriteLine($"Processing configuration from: {configPath}");

        // Read configuration file
        var configLines = await File.ReadAllLinesAsync(configPath);
        var config = new Dictionary<string, object>();

        foreach (var line in configLines)
        {
            if (line.Contains("=") && !line.TrimStart().StartsWith("#"))
            {
                var parts = line.Split('=', 2);
                var key = parts[0].Trim();
                var value = parts[1].Trim();

                // Smart parsing based on key name and value format
                try
                {
                    if (key.ToLower().Contains("enable") || key.ToLower().Contains("disable") || 
                        _boolParser.TryParse(value, out bool boolValue))
                    {
                        config[key] = boolValue;
                    }
                    else if (key.ToLower().Contains("date") || key.ToLower().Contains("time") ||
                            DateTime.TryParse(value, out DateTime dateValue))
                    {
                        config[key] = _dateParser.TryParse(value, DateTime.MinValue);
                    }
                    else if (key.ToLower().Contains("size") || value.ToUpper().EndsWith("B"))
                    {
                        config[key] = _converterRegistry.Convert<string, FileSize>(value);
                    }
                    else if (key.ToLower().Contains("timeout") || key.ToLower().Contains("interval"))
                    {
                        config[key] = ParseTimeSpan(value);
                    }
                    else if (int.TryParse(value, out int intValue))
                    {
                        config[key] = intValue;
                    }
                    else if (decimal.TryParse(value, out decimal decimalValue))
                    {
                        config[key] = decimalValue;
                    }
                    else
                    {
                        config[key] = StringUtil.CleanText(value);
                    }
                }
                catch (Exception ex)
                {
                    Console.WriteLine($"Warning: Could not parse {key}={value}: {ex.Message}");
                    config[key] = value; // Keep as string
                }
            }
        }

        Console.WriteLine("Parsed configuration:");
        foreach (var kvp in config)
        {
            Console.WriteLine($"  {kvp.Key}: {kvp.Value} ({kvp.Value.GetType().Name})");
        }

        // Validate configuration
        await ValidateConfiguration(config);
    }

    private TimeSpan ParseTimeSpan(string value)
    {
        // Handle various time formats
        if (value.EndsWith("ms"))
        {
            return TimeSpan.FromMilliseconds(int.Parse(value[..^2]));
        }
        else if (value.EndsWith("s") && !value.EndsWith("ms"))
        {
            return TimeSpan.FromSeconds(int.Parse(value[..^1]));
        }
        else if (value.EndsWith("m") && !value.EndsWith("ms"))
        {
            return TimeSpan.FromMinutes(int.Parse(value[..^1]));
        }
        else if (value.EndsWith("h"))
        {
            return TimeSpan.FromHours(int.Parse(value[..^1]));
        }

        return TimeSpan.Parse(value);
    }

    private async Task ValidateConfiguration(Dictionary<string, object> config)
    {
        var validationTemplate = @"
Configuration Validation Report
Generated: {ValidationDate:yyyy-MM-dd HH:mm:ss}

Configuration Summary:
- Total Settings: {TotalSettings}
- Valid Settings: {ValidSettings}
- Invalid Settings: {InvalidSettings}

{if HasErrors}
Issues Found:
{foreach ValidationErrors}
- {Setting}: {Error}
{endforeach}
{else}
✓ All configuration settings are valid.
{endif}

{if HasWarnings}
Warnings:
{foreach ValidationWarnings}
- {Setting}: {Warning}
{endforeach}
{endif}

Recommendations:
{foreach Recommendations}
- {Recommendation}
{endforeach}
";

        var errors = new List<object>();
        var warnings = new List<object>();
        var recommendations = new List<string>();

        // Validate settings
        foreach (var setting in config)
        {
            try
            {
                switch (setting.Key.ToLower())
                {
                    case "maxfilesize":
                        if (setting.Value is FileSize size && size.Bytes > 100 * 1024 * 1024) // 100MB
                        {
                            warnings.Add(new { Setting = setting.Key, Warning = "Large file size may impact performance" });
                        }
                        break;

                    case "connectiontimeout":
                        if (setting.Value is TimeSpan timeout && timeout.TotalSeconds < 5)
                        {
                            warnings.Add(new { Setting = setting.Key, Warning = "Very short timeout may cause connection issues" });
                        }
                        break;

                    case "enabledebug":
                        if (setting.Value is bool debug && debug)
                        {
                            recommendations.Add("Debug mode is enabled - consider disabling in production");
                        }
                        break;
                }
            }
            catch (Exception ex)
            {
                errors.Add(new { Setting = setting.Key, Error = ex.Message });
            }
        }

        // Add recommendations
        if (!config.ContainsKey("LogLevel"))
        {
            recommendations.Add("Consider adding LogLevel setting for better diagnostics");
        }

        if (!config.ContainsKey("BackupEnabled"))
        {
            recommendations.Add("Consider enabling backup functionality");
        }

        var validationData = new
        {
            ValidationDate = DateTime.Now,
            TotalSettings = config.Count,
            ValidSettings = config.Count - errors.Count,
            InvalidSettings = errors.Count,
            HasErrors = errors.Count > 0,
            HasWarnings = warnings.Count > 0,
            ValidationErrors = errors,
            ValidationWarnings = warnings,
            Recommendations = recommendations.Select(r => new { Recommendation = r })
        };

        var report = _templateProcessor.Process(validationTemplate, validationData);
        Console.WriteLine(report);

        // Save validation report
        var reportPath = "configuration_validation_report.txt";
        await File.WriteAllTextAsync(reportPath, report);
        Console.WriteLine($"Validation report saved to: {reportPath}");
    }

    public async Task ProcessDataFiles(string inputDirectory, string outputDirectory)
    {
        Console.WriteLine($"Processing data files from {inputDirectory} to {outputDirectory}");

        // Ensure output directory exists
        IOUtils.EnsureDirectoryExists(outputDirectory);

        // Find all data files
        var dataFiles = IOUtils.FindFiles(inputDirectory, "*.txt", SearchOption.AllDirectories);

        Console.WriteLine($"Found {dataFiles.Count()} data files to process");

        // Process files with progress
        var progress = new Progress<int>(processed =>
        {
            Console.WriteLine($"Processed {processed} files...");
        });

        await IOUtils.ProcessFilesAsync(dataFiles, async file =>
        {
            await ProcessSingleDataFile(file, outputDirectory);
        }, maxConcurrency: Environment.ProcessorCount, progress: progress);

        Console.WriteLine("Data processing completed");
    }

    private async Task ProcessSingleDataFile(string filePath, string outputDirectory)
    {
        var fileName = Path.GetFileNameWithoutExtension(filePath);
        var outputPath = Path.Combine(outputDirectory, $"{fileName}_processed.txt");

        // Read file content
        var content = await File.ReadAllTextAsync(filePath);

        // Clean and process content
        var lines = content.Split('\n');
        var processedLines = new List<string>();

        foreach (var line in lines)
        {
            var cleanLine = StringUtil.CleanText(line);

            if (!string.IsNullOrWhiteSpace(cleanLine))
            {
                // Apply various text processing
                var processed = cleanLine;

                // Standardize boolean values
                processed = StandardizeBooleans(processed);

                // Standardize dates
                processed = StandardizeDates(processed);

                // Clean and format
                processed = StringUtil.CleanText(processed);

                processedLines.Add(processed);
            }
        }

        // Generate summary
        var summary = $@"
// File: {Path.GetFileName(filePath)}
// Processed: {DateTime.Now:yyyy-MM-dd HH:mm:ss}
// Original lines: {lines.Length}
// Processed lines: {processedLines.Count}
// 
";

        var finalContent = summary + string.Join(Environment.NewLine, processedLines);

        // Write processed file
        await File.WriteAllTextAsync(outputPath, finalContent);
    }

    private string StandardizeBooleans(string text)
    {
        // Find and replace boolean-like values
        var boolPatterns = new[] { "yes", "no", "true", "false", "on", "off", "enabled", "disabled" };

        foreach (var pattern in boolPatterns)
        {
            if (text.ToLower().Contains(pattern))
            {
                try
                {
                    bool value = _boolParser.Parse(pattern);
                    text = text.Replace(pattern, value.ToString().ToLower(), StringComparison.OrdinalIgnoreCase);
                }
                catch { /* Ignore parsing errors */ }
            }
        }

        return text;
    }

    private string StandardizeDates(string text)
    {
        // Simple date standardization (in practice, would be more sophisticated)
        var datePatterns = new[]
        {
            @"\d{1,2}/\d{1,2}/\d{4}",
            @"\d{1,2}-\d{1,2}-\d{4}",
            @"\d{4}-\d{1,2}-\d{1,2}"
        };

        foreach (var pattern in datePatterns)
        {
            var matches = System.Text.RegularExpressions.Regex.Matches(text, pattern);
            foreach (System.Text.RegularExpressions.Match match in matches)
            {
                try
                {
                    var date = _dateParser.Parse(match.Value);
                    text = text.Replace(match.Value, date.ToString("yyyy-MM-dd"));
                }
                catch { /* Ignore parsing errors */ }
            }
        }

        return text;
    }

    public void GenerateProcessingReport(string outputPath)
    {
        var reportTemplate = @"
Data Processing Report
=====================

Processing Summary:
- Start Time: {StartTime:yyyy-MM-dd HH:mm:ss}
- End Time: {EndTime:yyyy-MM-dd HH:mm:ss}
- Duration: {Duration}
- Files Processed: {FilesProcessed}
- Total Data Size: {TotalDataSize}

Performance Metrics:
- Average Processing Time per File: {AverageProcessingTime}
- Files per Second: {FilesPerSecond:F2}
- Data Throughput: {DataThroughput}

System Information:
- Processor Count: {ProcessorCount}
- Available Memory: {AvailableMemory}
- Disk Space: {DiskSpace}

Generated by ByteForge Toolkit Data Processing Service
Generated on: {ReportDate:yyyy-MM-dd HH:mm:ss}
";

        var reportData = new
        {
            StartTime = DateTime.Now.AddHours(-2),
            EndTime = DateTime.Now,
            Duration = TimeSpan.FromHours(2),
            FilesProcessed = 1250,
            TotalDataSize = "2.5 GB",
            AverageProcessingTime = "0.85 seconds",
            FilesPerSecond = 0.17,
            DataThroughput = "1.25 MB/s",
            ProcessorCount = Environment.ProcessorCount,
            AvailableMemory = "8.2 GB",
            DiskSpace = "125 GB available",
            ReportDate = DateTime.Now
        };

        var report = _templateProcessor.Process(reportTemplate, reportData);
        File.WriteAllText(outputPath, report);

        Console.WriteLine($"Processing report generated: {outputPath}");
    }
}

// Helper class for file size handling
public class FileSize
{
    public long Bytes { get; }

    public FileSize(long bytes)
    {
        Bytes = bytes;
    }

    public override string ToString()
    {
        if (Bytes >= 1024L * 1024L * 1024L)
            return $"{Bytes / (1024.0 * 1024.0 * 1024.0):F2} GB";
        if (Bytes >= 1024L * 1024L)
            return $"{Bytes / (1024.0 * 1024.0):F2} MB";
        if (Bytes >= 1024L)
            return $"{Bytes / 1024.0:F2} KB";
        return $"{Bytes} B";
    }
}

// Main application
public class Program
{
    static async Task Main(string[] args)
    {
        var service = new DataProcessingService();

        try
        {
            Console.WriteLine("Starting data processing service...");

            // Process configuration
            await service.ProcessConfigurationFile("app.config");

            // Process data files
            await service.ProcessDataFiles(@"C:\Data\Input", @"C:\Data\Output");

            // Generate report
            service.GenerateProcessingReport("processing_report.txt");

            Console.WriteLine("Data processing completed successfully!");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
        }
    }
}

